// Dedup check for contact form - prevent duplicate notifications within 10 minutes
const body = $input.first().json.body || $input.first().json;
const email = body.email || body.from || 'unknown';
const message = body.message || body.content || '';
// Simple hash: first 20 chars of message
const msgHash = message.substring(0, 20).toLowerCase().replace(/[^a-z0-9]/g,'');
const key = 'dedup_contact_' + email.toLowerCase().replace(/[^a-z0-9]/g,'') + '_' + msgHash;
const now = Date.now();
const ttl = 10 * 60 * 1000;

const stored = $getWorkflowStaticData('global');
if (!stored.dedup) stored.dedup = {};

for (const k of Object.keys(stored.dedup)) {
  if (now - stored.dedup[k] > ttl) {
    delete stored.dedup[k];
  }
}

if (stored.dedup[key]) {
  return [];
}
stored.dedup[key] = now;
return $input.all();

const rawData = $input.item.json;
const data = rawData.body || rawData;

const name = data.name || 'N/A';
const email = data.email || 'N/A';
const subject = data.subject || 'N/A';
const message = data.message || 'N/A';
const source = data.source || 'Contact Form – The Unnamed Roads';
const ts = new Date().toLocaleString('sv-SE', { timeZone: 'Europe/Stockholm' });

const text = `\u{1F4EC} <b>Ny kontaktförfrågan – ${source}</b>\n\n<b>Namn:</b> ${name}\n<b>E-post:</b> ${email}\n<b>Ämne:</b> ${subject}\n<b>Meddelande:</b> ${message}\n<b>Källa:</b> ${source}\n<b>Tid:</b> ${ts}`;

const token = $env.TELEGRAM_BOT_TOKEN || '8683132686:AAF5yJ206OcLKsSBx0n4Nm4uBAxcQlRbwyc';
const chatId = '-1003767033253';

try {
  const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
  });
  return [{ json: { success: response.ok, status: response.status } }];
} catch (e) {
  return [{ json: { success: false, error: e.message } }];
}
